package com.recettealarm.app;
import android.app.*;import android.content.*;import android.database.*;import android.graphics.Typeface;import android.net.*;import android.os.*;import android.widget.*;
public class DetailActivity extends Activity{long id;DB db;String videos="",title="Recette";public void onCreate(Bundle b){super.onCreate(b);db=new DB(this);id=getIntent().getLongExtra("id",0);}public void onResume(){super.onResume();draw();}
 void draw(){LinearLayout r=UI.root(this);Button back=UI.whiteBtn(this,"← Retour");r.addView(back);back.setOnClickListener(v->finish());Cursor c=db.one(id);String img="",cat="",water="";int time=0,serv=0,rat=0,fav=0;if(c.moveToFirst()){title=s(c,"title");cat=s(c,"category");videos=s(c,"video");img=s(c,"image");time=c.getInt(c.getColumnIndexOrThrow("time"));serv=c.getInt(c.getColumnIndexOrThrow("servings"));rat=c.getInt(c.getColumnIndexOrThrow("rating"));water=s(c,"water_liters");try{fav=c.getInt(c.getColumnIndexOrThrow("fav"));}catch(Exception e){}}c.close();r.addView(UI.image(this,img,210));LinearLayout row=UI.row(this);row.addView(UI.tv(this,title,30,Typeface.BOLD),new LinearLayout.LayoutParams(0,-2,1));row.addView(UI.pill(this,cat,UI.terracotta));r.addView(row);TextView stars=UI.tv(this,UI.stars(rat)+"   "+(fav==1?"❤ Favori":""),22,Typeface.BOLD);stars.setTextColor(UI.gold);r.addView(stars);r.addView(UI.muted(this,"⏱ "+time+" min   •   👥 "+serv+" personnes",16));if(water!=null&&water.trim().length()>0)r.addView(UI.smallCard(this,"💧 Liquide conseillé : "+water+"\nRepère : 1 L ≈ 5 verres de 200 ml"));
 Button cook=UI.btn(this,"▶ Démarrer la cuisine");r.addView(cook);cook.setOnClickListener(v->startActivity(new Intent(this,CookingActivity.class).putExtra("id",id)));Button edit=UI.whiteBtn(this,"⚙ Modifier / Admin");r.addView(edit);edit.setOnClickListener(v->startActivity(new Intent(this,EditRecipeActivity.class).putExtra("id",id)));Button favBtn=UI.oliveBtn(this,fav==1?"♡ Retirer favori":"❤ Mettre en favori");r.addView(favBtn);int nf=fav==1?0:1;favBtn.setOnClickListener(v->{db.fav(id,nf);draw();});
 Button shop=UI.whiteBtn(this,"🛒 Liste de courses de cette recette");r.addView(shop);shop.setOnClickListener(v->startActivity(new Intent(this,ShoppingActivity.class).putExtra("recipe_id",id)));
 addVideos(r);
 r.addView(UI.tv(this,"Ingrédients",24,Typeface.BOLD));LinearLayout ingBox=UI.section(this);Cursor i=db.ingredients(id);int count=0;while(i.moveToNext()){count++;ingBox.addView(UI.smallCard(this,"🥕 "+i.getString(2)+"     "+i.getString(3)+" "+i.getString(4)));}i.close();if(count==0)ingBox.addView(UI.smallCard(this,"Aucun ingrédient encore."));r.addView(ingBox);
 r.addView(UI.tv(this,"Étapes anti-brûlure",24,Typeface.BOLD));Cursor s=db.steps(id);int stepCount=0;while(s.moveToNext()){stepCount++;int temp=s.getInt(7);String media=s.getString(8);String t="🔥 Étape "+s.getInt(2)+"   •   ⏱ "+s.getInt(4)+" min"+(temp>0?"   •   🌡 "+temp+"°C":"")+"\n"+s.getString(3)+"\n⚠ "+s.getString(6);if(media!=null&&media.trim().length()>0)t += "\n🎬 Média : "+media; r.addView(UI.card(this,t));}s.close();if(stepCount==0)r.addView(UI.smallCard(this,"Ajoute au moins une étape avant de lancer la cuisine."));}
 void addVideos(LinearLayout r){if(videos==null||videos.trim().length()==0)return;r.addView(UI.tv(this,"Vidéos",24,Typeface.BOLD));String[] lines=videos.split("\\n|,|;");int n=1;for(String raw:lines){String u=raw.trim();if(u.length()<5)continue;Button b=UI.whiteBtn(this,"🎥 Ouvrir vidéo "+n);r.addView(b);b.setOnClickListener(v->{try{startActivity(new Intent(Intent.ACTION_VIEW,Uri.parse(u)));}catch(Exception e){UI.toast(this,"Lien vidéo invalide");}});n++;}}
 String s(Cursor c,String col){try{String x=c.getString(c.getColumnIndexOrThrow(col));return x==null?"":x;}catch(Exception e){return "";}}}
